import { _decorator, Component, Node } from 'cc';
const { ccclass, property } = _decorator;
import Emitter from 'events';

interface listenerType {
    event: string,
    listener: Function
}

@ccclass('mEmitter')
class mEmitter {
    static instance: mEmitter;
    private _emitter: Emitter;
    private eventListeners = new Map<Node, listenerType[]>();
    constructor() {
        if (Emitter.instance) {
            return Emitter.instance;
        }
        this._emitter = new Emitter();
        this._emitter.setMaxListeners(100);
        mEmitter.instance = this._emitter;
        console.log("finish emitter")
    }

    emit(...args) {
        this._emitter.emit(...args);
    }

    registerEvent(event: string, listener: Function, node: Node) {
        this._emitter.on(event, listener);
        if (!this.eventListeners.has(node)) {
            this.eventListeners.set(node, []);
        }
        for (let listener of this.eventListeners.get(node)) {
            if (listener.event === event) {
                return;
            }
        }
        this.eventListeners.get(node).push({ event: event, listener: listener })
    }
    registerOnce(event: string, listener: Function, node: Node) {
        this._emitter.once(event, listener);
    }

    removeEvent(event: string, listener: Function, node: Node) {
        this._emitter.removeListener(event, listener);
        this.eventListeners.delete(node);
    }

    removeAllEvent(node: Node) {
        this.eventListeners.get(node).forEach((listener, event) => {
            this._emitter.removeListener(event, listener);
        });
        this.eventListeners.clear();
    }

    destroy() {
        this._emitter.removeAllListeners();
        this._emitter = null;
        mEmitter.instance = null;
    }
}
Emitter.instance = null;
export { mEmitter };